package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfa.bijdrage;

import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.RszConstant;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplStatuutDmfappl;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Pensioenstelsel;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.rsz.RszConstantType;
import be.schaubroeck.lpb.tools.rsz.dmfa.Eredienst;
import be.schaubroeck.lpb.tools.service.RszConstantService;
import lombok.AllArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.util.EnumSet;
import java.util.Set;

@Slf4j
@AllArgsConstructor
public class RegelingSpeciaalPensioenStelsel {

    private static final Set<Pensioenstelsel> SPECIAAL_PENSIOENSTELSEL = EnumSet.of(
            Pensioenstelsel.KLASSIEK_STAATSREGIME,
            Pensioenstelsel.POOL_DER_PARASTALEN,
            Pensioenstelsel.GESOLIDAR_PENSIOENFONDS_EX_GEMEEN,
            Pensioenstelsel.GESOLIDAR_PENSIOENFONDS_ANDERE);

    private final RszConstantService rszConstantService;
    private final RegulManager regulManager;

    public boolean check(Pensioenstelsel pensioenStelsel) {
        return SPECIAAL_PENSIOENSTELSEL.contains(pensioenStelsel);
    }

    public RszConstant getRszConstant(SleutelGegevens gegevens, LocalDate zoekDatum) {
        DmfapplWnkengetal werknemersKengetal = gegevens.getWerknemersKengetal();
        Pensioenstelsel pensioenStelsel = gegevens.getPensioenStelsel();
        RszConstant constante = null;
        if (werknemersKengetal == DmfapplWnkengetal.STAGIAIR_VASTBENOEM_VAK_PRIVE_DMFA) {
            constante = getRszConstants677(gegevens, pensioenStelsel, zoekDatum);
        } else if (heeftPensioenstelsel25To28NonEredienst(werknemersKengetal, gegevens.getStatuutDmfappl())) {
            constante = getRszConstantsPensioenstelsel25To28NonEredienst(gegevens, pensioenStelsel, zoekDatum);
        } else {
            regulManager.doRegulException(gegevens.getOpdracht(), Regulkode.NIET_GEPROGRAMMEERD);
        }

        return constante;
    }

    private static boolean heeftPensioenstelsel25To28NonEredienst(DmfapplWnkengetal werknemersKengetal, DmfapplStatuutDmfappl statuut) {
        boolean is675Of676 = werknemersKengetal == DmfapplWnkengetal.VASTBENOEMDE || werknemersKengetal == DmfapplWnkengetal.STATUTAIREN_STANDPLAATS_BUITENLAND;
        return is675Of676 && Eredienst.hasPensioenBijdrage(statuut);
    }

    private RszConstant getRszConstants677(SleutelGegevens gegevens, Pensioenstelsel pensioenStelsel, LocalDate zoekDatum) {
        RszConstant constante = null;
        if (pensioenStelsel == Pensioenstelsel.KLASSIEK_STAATSREGIME) {
            constante = rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(
                    gegevens.getWerkgeversCategorie(), DmfapplWnkengetal.MANDATARISSEN_OF_STAFFUNCTIE, RszConstantType.TYPE_0.getCode(), zoekDatum);
        } else if (pensioenStelsel == Pensioenstelsel.POOL_DER_PARASTALEN) {
            constante = rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(
                    gegevens.getWerkgeversCategorie(), DmfapplWnkengetal.MANDATARISSEN_OF_STAFFUNCTIE, RszConstantType.TYPE_1.getCode(), zoekDatum);
        } else if (pensioenStelsel == Pensioenstelsel.GESOLIDAR_PENSIOENFONDS_EX_GEMEEN) {
            constante = rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(
                    gegevens.getWerkgeversCategorie(), DmfapplWnkengetal.BASISPENSIOENBIJDR_GEWESTELIJKE_ONTVANGERS, RszConstantType.TYPE_0.getCode(), zoekDatum);
        } else if (pensioenStelsel == Pensioenstelsel.GESOLIDAR_PENSIOENFONDS_ANDERE) {
            constante = rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(
                    gegevens.getWerkgeversCategorie(), DmfapplWnkengetal.BASISPENSIOENBIJDR_GEWESTELIJKE_ONTVANGERS, RszConstantType.TYPE_1.getCode(), zoekDatum);
        } else {
            regulManager.doRegulException(gegevens.getOpdracht(), Regulkode.NIET_GEPROGRAMMEERD);
        }

        return constante;
    }

    private RszConstant getRszConstantsPensioenstelsel25To28NonEredienst(SleutelGegevens gegevens, Pensioenstelsel pensioenStelsel, LocalDate zoekDatum) {
        RszConstant constante = null;
        switch (pensioenStelsel) {
            case KLASSIEK_STAATSREGIME -> constante = rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(
                    gegevens.getWerkgeversCategorie(), DmfapplWnkengetal.BASISPENSBIJDR_STATUTAIRE_WERKNEMERS, 0, zoekDatum);
            case POOL_DER_PARASTALEN -> constante = rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(
                    gegevens.getWerkgeversCategorie(), DmfapplWnkengetal.BASISPENSBIJDR_STATUTAIRE_WERKNEMERS, 1, zoekDatum);
            case GESOLIDAR_PENSIOENFONDS_EX_GEMEEN -> constante = rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(
                    gegevens.getWerkgeversCategorie(), DmfapplWnkengetal.BASISPENSIOENBIJDR_GEWESTELIJKE_ONTVANGERS, 0, zoekDatum);
            case GESOLIDAR_PENSIOENFONDS_ANDERE -> constante = rszConstantService.getByWerkgeversCategorieEnWerknemersKengetalBijdrageEnDatum(
                    gegevens.getWerkgeversCategorie(), DmfapplWnkengetal.BASISPENSIOENBIJDR_GEWESTELIJKE_ONTVANGERS, 1, zoekDatum);
            default -> {
                log.debug("Speciaal pensioenstelsel met code {}  is niet geimplementeerd", pensioenStelsel.getCode());
                regulManager.doRegulException(gegevens.getOpdracht(), Regulkode.NIET_GEPROGRAMMEERD);
            }
        }
        return constante;
    }
}
